","/**
 * ServiceNow API helpers for the Control Tower page.
 * Uses the Aggregate (/stats) and Table APIs.
 */

const HEADERS: Record<string, string> = {
 Accept: "application/json",
 "Content-Type": "application/json",
};

function authHeaders(): Record<string, string> {
 const token = (window as any).g_ck;
 return token ? { ...HEADERS, "X-UserToken": token } : HEADERS;
}

/* ── Aggregate count ──────────────────────────────────────── */

export async function fetchCount(
 table: string,
 query: string,
): Promise<number> {
 const params = new URLSearchParams({
 sysparm_query: query,
 sysparm_count: "true",
 });
 const res = await fetch(`/api/now/stats/${table}?${params}`, {
 headers: authHeaders(),
 });
 const json = await res.json();
 return parseInt(json?.result?.stats?.count ?? "0", 10);
}

/* ── Aggregate average ────────────────────────────────────── */

export async function fetchAvg(
 table: string,
 query: string,
 field: string,
): Promise<number> {
 const params = new URLSearchParams({
 sysparm_query: query,
 sysparm_avg_fields: field,
 });
 const res = await fetch(`/api/now/stats/${table}?${params}`, {
 headers: authHeaders(),
 });
 const json = await res.json();
 const avg = json?.result?.stats?.avg?.[field];
 return avg ? parseFloat(avg) : 0;
}

/* ── Grouped aggregate counts ─────────────────────────────── */

export interface GroupCount {
 label: string;
 value: string;
 count: number;
}

export async function fetchGroupedStats(
 table: string,
 query: string,
 groupBy: string,
): Promise<GroupCount[]> {
 const params = new URLSearchParams({
 sysparm_query: query,
 sysparm_count: "true",
 sysparm_group_by: groupBy,
 sysparm_display_value: "true",
 });
 const res = await fetch(`/api/now/stats/${table}?${params}`, {
 headers: authHeaders(),
 });
 const json = await res.json();
 const results: any[] = json?.result ?? [];
 return results.map((r) => ({
 label: r?.groupby_fields?.[0]?.display_value || r?.groupby_fields?.[0]?.value || "Unknown",
 value: r?.groupby_fields?.[0]?.value || "",
 count: parseInt(r?.stats?.count ?? "0", 10),
 }));
}

/* ── Table API (record fetch) ─────────────────────────────── */

export async function fetchRecords(
 table: string,
 query: string,
 fields: string,
 limit: number = 500,
): Promise<any[]> {
 const params = new URLSearchParams({
 sysparm_query: query,
 sysparm_fields: fields,
 sysparm_display_value: "all",
 sysparm_limit: String(limit),
 });
 const res = await fetch(`/api/now/table/${table}?${params}`, {
 headers: authHeaders(),
 });
 const json = await res.json();
 return json?.result ?? [];
}

/* ── Workspace variable filters from URL params ───────────── */

export function getFilterParams(): { company: string; site: string } {
 const sp = new URLSearchParams(window.location.search);
 return { company: sp.get("company") || "", site: sp.get("site") || "" };
}

export function companyFilter(field: string = "company"): string {
 const { company, site } = getFilterParams();
 let q = "";
 if (company) q += `${field}=${company}`;
 if (site) q += `${q ? "^" : ""}isa_entity_site=${site}`;
 return q;
}
