type Status = "RUNNING" | "DEGRADED" | "STOPPED" | "LOADING";

function statusClass(s: Status): string {
 if (s === "RUNNING") return "ct-line--running";
 if (s === "DEGRADED") return "ct-line--degraded";
 if (s === "STOPPED") return "ct-line--stopped";
 return "";
}

export default function LineStatusCard({ label, keywords, refreshKey }: Props) {
 const [total, setTotal] = useState(0);
 const [critical, setCritical] = useState(0);
 const [status, setStatus] = useState<Status>("LOADING");

 useEffect(() => {
 let cancelled = false;
 async function load() {
 setStatus("LOADING");
 const cf = companyFilter();
 // Build OR clause for line name matching
 const nameClause = keywords
 .map((k) => `cmdb_ci.nameLIKE${k}`)
 .join("^OR");
 const base = `active=true^(${nameClause})${cf ? "^" + cf : ""}`;

 const [t, c] = await Promise.all([
 fetchCount("sn_ot_incident", base),
 fetchCount("sn_ot_incident", `${base}^priority=1`),
 ]);
 if (cancelled) return;
 setTotal(t);
 setCritical(c);
 setStatus(t === 0 ? "RUNNING" : c > 0 ? "STOPPED" : "DEGRADED");
 }
 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 return (
 <div className={`ct-line-card ${statusClass(status)}`}>
 <div className="ct-line-card__name">{label}</div>
 <div className="ct-line-card__status">
 {status === "LOADING" ? "…" : status}
 </div>
 <div className="ct-line-card__subtitle">
 {status !== "LOADING" ? `${total} active incident${total !== 1 ? "s" : ""}` : ""}
 </div>
 </div>
 );
}
