","import React, { useState } from "react";
import { useSitePins, SitePin } from "../hooks/useSitePins";

const PAD = 24;

function pinColor(hp: number): string {
 if (hp === 1) return "#f44336";
 if (hp === 2) return "#ff9800";
 return "#ffeb3b";
}

function pinGlow(hp: number): string {
 if (hp === 1) return "rgba(244,67,54,0.4)";
 if (hp === 2) return "rgba(255,152,0,0.3)";
 return "rgba(255,235,59,0.2)";
}

/** Simple equirectangular projection. */
function project(lat: number, lng: number, w: number, h: number) {
 return {
 x: PAD + ((lng + 180) / 360) * (w - PAD * 2),
 y: PAD + ((90 - lat) / 180) * (h - PAD * 2),
 };
}

function pinRadius(total: number): number {
 return Math.min(6 + total * 1.5, 16);
}

interface Props {
 refreshKey: number;
}

export default function IncidentMap({ refreshKey }: Props) {
 const { pins, loading } = useSitePins(refreshKey);
 const [hover, setHover] = useState<SitePin | null>(null);
 const [mouse, setMouse] = useState({ x: 0, y: 0 });

 const W = 640;
 const H = 320;

 return (
 <div className="ct-map">
 <div className="ct-section-label">Incident Heat Map</div>
 <div
 className="ct-map__canvas"
 onMouseMove={(e) => {
 const rect = e.currentTarget.getBoundingClientRect();
 setMouse({ x: e.clientX - rect.left, y: e.clientY - rect.top });
 }}
 >
 <svg viewBox={`0 0 ${W} ${H}`} className="ct-map__svg">
 {/* Grid lines */}
 {[0, 30, 60, 90, 120, 150, 180].map((g) => {
 const { x } = project(0, g - 180, W, H);
 const { x: x2 } = project(0, g, W, H);
 return (
 <React.Fragment key={`lg${g}`}>
 <line x1={x} y1={PAD} x2={x} y2={H - PAD} className="ct-map__grid" />
 <line x1={x2} y1={PAD} x2={x2} y2={H - PAD} className="ct-map__grid" />
 </React.Fragment>
 );
 })}
 {[-60, -30, 0, 30, 60].map((lat) => {
 const { y } = project(lat, 0, W, H);
 return <line key={`lt${lat}`} x1={PAD} y1={y} x2={W - PAD} y2={y} className="ct-map__grid" />;
 })}

 {/* Pins */}
 {pins.map((pin) => {
 const { x, y } = project(pin.lat, pin.lng, W, H);
 const r = pinRadius(pin.total);
 return (
 <g
 key={pin.siteId}
 onMouseEnter={() => setHover(pin)}
 onMouseLeave={() => setHover(null)}
 style={{ cursor: "pointer" }}
 >
 <circle cx={x} cy={y} r={r + 4} fill={pinGlow(pin.highestPriority)} />
 <circle cx={x} cy={y} r={r} fill={pinColor(pin.highestPriority)} opacity={0.9} />
 <text x={x} y={y + 3} textAnchor="middle" className="ct-map__pin-count">
 {pin.total}
 </text>
 </g>
 );
 })}

 {/* Empty state */}
 {!loading && pins.length === 0 && (
 <text x={W / 2} y={H / 2} textAnchor="middle" className="ct-map__empty">
 No active incidents with site locations
 </text>
 )}
 </svg>

 {/* Tooltip */}
 {hover && (
 <div className="ct-map__tooltip" style={{ left: mouse.x + 12, top: mouse.y - 8 }}>
 <strong>{hover.siteName}</strong>
 <span>{hover.total} incident{hover.total !== 1 ? "s" : ""}</span>
 {hover.critical > 0 && <span className="ct-tt-crit">{hover.critical} Critical</span>}
 {hover.high > 0 && <span className="ct-tt-high">{hover.high} High</span>}
 {hover.medium > 0 && <span className="ct-tt-med">{hover.medium} Medium</span>}
 </div>
 )}
 </div>
 </div>
 );
}
","import { useState, useEffect } from "react";
import { fetchRecords, companyFilter } from "../services/api";

export interface SitePin {
 siteId: string;
 siteName: string;
 lat: number;
 lng: number;
 total: number;
 critical: number;
 high: number;
 medium: number;
 highestPriority: number;
}

/**
 * Fetches active OT incidents (priority 1-3), resolves site
 * locations via cmdb_ci_ot_isa_entity → cmn_location, and
 * returns an array of SitePin objects for map rendering.
 */
export function useSitePins(refreshKey: number) {
 const [pins, setPins] = useState<SitePin[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 let cancelled = false;
 async function load() {
 setLoading(true);
 const cf = companyFilter();
 const incQ = `active=true^priorityIN1,2,3${cf ? "^" + cf : ""}`;

 // 1 — Fetch incidents with site reference
 const incidents = await fetchRecords(
 "sn_ot_incident",
 incQ,
 "isa_entity_site,priority",
 500,
 );

 // 2 — Group by site
 const siteMap: Record<string, { total: number; critical: number; high: number; medium: number }> = {};
 for (const inc of incidents) {
 const id = inc.isa_entity_site?.value;
 if (!id) continue;
 if (!siteMap[id]) siteMap[id] = { total: 0, critical: 0, high: 0, medium: 0 };
 siteMap[id].total++;
 const p = parseInt(inc.priority?.value ?? "4", 10);
 if (p === 1) siteMap[id].critical++;
 else if (p === 2) siteMap[id].high++;
 else if (p === 3) siteMap[id].medium++;
 }

 const siteIds = Object.keys(siteMap);
 if (siteIds.length === 0) {
 if (!cancelled) { setPins([]); setLoading(false); }
 return;
 }

 // 3 — Fetch site records with location reference
 const sites = await fetchRecords(
 "cmdb_ci_ot_isa_entity",
 `sys_idIN${siteIds.join(",")}`,
 "sys_id,name,location",
 200,
 );

 const locIds = sites.map((s) => s.location?.value).filter(Boolean);
 if (locIds.length === 0) {
 if (!cancelled) { setPins([]); setLoading(false); }
 return;
 }

 // 4 — Fetch locations for lat/lng
 const locations = await fetchRecords(
 "cmn_location",
 `sys_idIN${[...new Set(locIds)].join(",")}`,
 "sys_id,latitude,longitude,name",
 200,
 );
 const locMap: Record<string, { lat: number; lng: number }> = {};
 for (const loc of locations) {
 const lat = parseFloat(loc.latitude?.value ?? loc.latitude ?? "0");
 const lng = parseFloat(loc.longitude?.value ?? loc.longitude ?? "0");
 if (lat !== 0 || lng !== 0) locMap[loc.sys_id?.value ?? loc.sys_id] = { lat, lng };
 }

 // 5 — Assemble pins
 const result: SitePin[] = [];
 for (const site of sites) {
 const sid = site.sys_id?.value ?? site.sys_id;
 const lid = site.location?.value;
 const coord = lid ? locMap[lid] : null;
 const data = siteMap[sid];
 if (!coord || !data) continue;
 const hp = data.critical > 0 ? 1 : data.high > 0 ? 2 : 3;
 result.push({
 siteId: sid,
 siteName: site.name?.display_value || site.name?.value || "Site",
 lat: coord.lat,
 lng: coord.lng,
 ...data,
 highestPriority: hp,
 });
 }

 if (!cancelled) { setPins(result); setLoading(false); }
 }
 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 return { pins, loading };
}
