 className="ct-bar-fill"
 style={{
 width: `${(item.count / max) * 100}%`,
 background: barColor(item.label, i),
 }}
 />
 </div>
 <div className="ct-bar-count">{item.count}</div>
 </div>
 ))}
 </div>
 </div>
 );
