","import React, { useState, useEffect } from "react";
import { fetchCount, fetchAvg, companyFilter } from "../services/api";

interface Props {
 refreshKey: number;
}

function formatDays(d: number): string {
 if (d === 0) return "N/A";
 const days = Math.floor(d);
 const hours = Math.round((d - days) * 24);
 if (days === 0) return `${hours}h`;
 return hours > 0 ? `${days}d ${hours}h` : `${days}d`;
}

function slaColor(pct: number): string {
 if (pct >= 95) return "#4caf50";
 if (pct >= 80) return "#ff9800";
 return "#f44336";
}

export default function VulnGauges({ refreshKey }: Props) {
 const [critCount, setCritCount] = useState<number | null>(null);
 const [mttr, setMttr] = useState<number | null>(null);
 const [slaPct, setSlaPct] = useState<number | null>(null);

 useEffect(() => {
 let cancelled = false;
 async function load() {
 const cf = companyFilter("cmdb_ci.company");
 const vulnBase = cf || "sys_idISNOTEMPTY";

 // 1 — Critical vulns (risk_rating=1, not closed)
 const critQ = `risk_rating=1^stateNOT IN3,101${cf ? "^" + cf : ""}`;
 const crit = await fetchCount("sn_vul_vulnerable_item", critQ);

 // 2 — MTTR: avg age_closed for vulns resolved in last 30 days
 const mttrQ = `resolution_dateISNOTEMPTY^resolution_dateRELATIVEGE@dayofweek@ago@30${cf ? "^" + cf : ""}`;
 const avg = await fetchAvg("sn_vul_vulnerable_item", mttrQ, "age_closed");

 // 3 — SLA compliance: OT incidents resolved in 30 days
 const incCf = companyFilter();
 const resolvedBase = `resolved_atISNOTEMPTY^resolved_atRELATIVEGE@dayofweek@ago@30${incCf ? "^" + incCf : ""}`;
 const [total, madeSla] = await Promise.all([
 fetchCount("sn_ot_incident", resolvedBase),
 fetchCount("sn_ot_incident", `${resolvedBase}^made_sla=true`),
 ]);

 if (cancelled) return;
 setCritCount(crit);
 setMttr(avg);
 setSlaPct(total > 0 ? Math.round((madeSla / total) * 100) : 100);
 }
 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 const loading = critCount === null;

 return (
 <div className="ct-vuln-gauges">
 <div className="ct-section-label">Vulnerability Risk Gauges</div>
 <div className="ct-gauge-row">
 <div className="ct-gauge">
 <span className={`ct-gauge__value ${critCount && critCount > 0 ? "ct-gauge__value--red" : "ct-gauge__value--green"}`}>
 {loading ? "…" : critCount}
 </span>
 <span className="ct-gauge__label">Critical Vulns</span>
 <span className="ct-gauge__sub">Unpatched Critical</span>
 </div>
 <div className="ct-gauge">
 <span className="ct-gauge__value ct-gauge__value--blue">
 {loading ? "…" : formatDays(mttr!)}
 </span>
 <span className="ct-gauge__label">MTTR</span>
 <span className="ct-gauge__sub">Avg Remediation Time</span>
 </div>
 <div className="ct-gauge">
 <span className="ct-gauge__value" style={{ color: slaPct !== null ? slaColor(slaPct) : "#c9d1d9" }}>
 {loading ? "…" : `${slaPct}%`}
 </span>
 <span className="ct-gauge__label">SLA Compliance</span>
 <span className="ct-gauge__sub">OT Incident SLA</span>
 </div>
 </div>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { fetchRecords, companyFilter } from "../services/api";

interface LevelData {
 id: string;
 label: string;
 shortLabel: string;
 count: number;
}

const LEVELS = [
 { id: "0", label: "Process", shortLabel: "L0" },
 { id: "1", label: "Basic Control", shortLabel: "L1" },
 { id: "2", label: "Supervisory", shortLabel: "L2" },
 { id: "3", label: "Site Ops", shortLabel: "L3" },
 { id: "3.5", label: "DMZ", shortLabel: "DMZ" },
 { id: "4", label: "Enterprise", shortLabel: "L4" },
];

function zoneColor(count: number): string {
 if (count === 0) return "#4caf50";
 if (count <= 2) return "#ff9800";
 return "#f44336";
}

interface Props {
 refreshKey: number;
}

export default function PurdueStatus({ refreshKey }: Props) {
 const [levels, setLevels] = useState<LevelData[]>(
 LEVELS.map((l) => ({ ...l, count: 0 })),
 );
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 let cancelled = false;
 async function load() {
 setLoading(true);
 const cf = companyFilter();
 const incQ = `active=true${cf ? "^" + cf : ""}`;

 // 1 — Fetch active OT incidents with site ref
 const incidents = await fetchRecords(
 "sn_ot_incident", incQ, "isa_entity_site", 500,
 );
 const siteIds = [...new Set(
 incidents.map((i: any) => i.isa_entity_site?.value).filter(Boolean),
 )];

 if (siteIds.length === 0) {
 if (!cancelled) {
 setLevels(LEVELS.map((l) => ({ ...l, count: 0 })));
 setLoading(false);
 }
 return;
 }

 // 2 — Fetch sites with isa_entity_level reference
 const sites = await fetchRecords(
 "cmdb_ci_ot_isa_entity",
 `sys_idIN${siteIds.join(",")}`,
 "sys_id,isa_entity_level",
 500,
 );

 // Build siteId → level display value map
 const siteLevel: Record<string, string> = {};
 for (const s of sites) {
 const sid = s.sys_id?.value ?? s.sys_id;
 const lv = s.isa_entity_level?.display_value || s.isa_entity_level?.value || "";
 siteLevel[sid] = lv;
 }

 // 3 — Count incidents per level
 const counts: Record<string, number> = {};
 for (const inc of incidents) {
 const sid = inc.isa_entity_site?.value;
 if (!sid || !siteLevel[sid]) continue;
 const lv = siteLevel[sid];
 counts[lv] = (counts[lv] || 0) + 1;
 }

 if (!cancelled) {
 setLevels(LEVELS.map((l) => ({
 ...l,
 count: counts[l.id] || counts[l.label] || counts[l.shortLabel] || 0,
 })));
 setLoading(false);
 }
 }
 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 return (
 <div className="ct-purdue">
 <div className="ct-section-label">Purdue Model — Zone Health</div>
 <div className="ct-purdue-row">
 {levels.map((lv) => (
 <div key={lv.id} className="ct-purdue-zone" title={`${lv.label}: ${lv.count} active incidents`}>
 <span className="ct-purdue-zone__short">{lv.shortLabel}</span>
 <span
 className="ct-purdue-zone__count"
 style={{ color: loading ? "#484f58" : zoneColor(lv.count) }}
 >
 {loading ? "…" : lv.count}
 </span>
 <span className="ct-purdue-zone__label">{lv.label}</span>
 </div>
 ))}
 </div>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { fetchRecords, companyFilter } from "../services/api";

interface Alert {
 sysId: string;
 time: string;
 priority: number;
 priorityLabel: string;
 description: string;
 category: string;
}

const PRI_COLORS: Record<number, string> = {
 1: "#f44336", 2: "#ff9800", 3: "#4fc3f7", 4: "#484f58", 5: "#484f58",
};
const PRI_LABELS: Record<number, string> = {
 1: "CRIT", 2: "HIGH", 3: "MED", 4: "LOW", 5: "LOW",
};

function truncate(s: string, n: number): string {
 return s.length > n ? s.slice(0, n) + "…" : s;
}

function formatTime(iso: string): string {
 try {
 const d = new Date(iso.replace(" ", "T") + "Z");
 return d.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false });
 } catch { return iso.slice(11, 16); }
}

function demoTime(minsAgo: number): string {
 const d = new Date(Date.now() - minsAgo * 60_000);
 return d.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false });
}

function recordUrl(sysId: string): string {
 return `/now/workspace/customer-site-ops/record/sn_si_incident/${sysId}`;
}

const DEMO_ALERTS: Alert[] = [
 { sysId: "", time: demoTime(2), priority: 1, priorityLabel: "CRIT", description: "Unauthorized PLC firmware write detected on Line 2 controller", category: "Nozomi" },
 { sysId: "", time: demoTime(5), priority: 2, priorityLabel: "HIGH", description: "Unmanaged device detected on OT VLAN 10 — MAC spoofing risk", category: "ARMIS" },
 { sysId: "", time: demoTime(8), priority: 1, priorityLabel: "CRIT", description: "Modbus TCP anomaly — unusual function code to RTU-07", category: "Nozomi" },
 { sysId: "", time: demoTime(12), priority: 2, priorityLabel: "HIGH", description: "ARMIS policy violation: engineering workstation running RDP", category: "ARMIS" },
 { sysId: "", time: demoTime(15), priority: 3, priorityLabel: "MED", description: "New asset discovered on segment 192.168.40.x — unclassified", category: "ARMIS" },
 { sysId: "", time: demoTime(19), priority: 2, priorityLabel: "HIGH", description: "Nozomi alert: ARP storm detected between HMI-03 and Switch-12", category: "Nozomi" },
 { sysId: "", time: demoTime(23), priority: 3, priorityLabel: "MED", description: "OT device firmware version mismatch — PLC-04 running v2.1", category: "ARMIS" },
 { sysId: "", time: demoTime(28), priority: 1, priorityLabel: "CRIT", description: "Cleartext credentials observed on Modbus session to DCS-01", category: "Nozomi" },
 { sysId: "", time: demoTime(35), priority: 3, priorityLabel: "MED", description: "ARMIS risk score increased for asset HMI-Panel-East to 8.4", category: "ARMIS" },
 { sysId: "", time: demoTime(42), priority: 2, priorityLabel: "HIGH", description: "DNS tunneling attempt from engineering subnet 10.20.5.x", category: "Nozomi" },
 { sysId: "", time: demoTime(50), priority: 3, priorityLabel: "MED", description: "Vulnerability CVE-2024-3400 detected on perimeter firewall", category: "ARMIS" },
 { sysId: "", time: demoTime(58), priority: 2, priorityLabel: "HIGH", description: "Nozomi: abnormal S7comm traffic pattern to Siemens S7-1500", category: "Nozomi" },
 { sysId: "", time: demoTime(65), priority: 4, priorityLabel: "LOW", description: "Scheduled scan completed — 3 new assets cataloged", category: "ARMIS" },
 { sysId: "", time: demoTime(72), priority: 3, priorityLabel: "MED", description: "OT network baseline deviation — 12% traffic increase on L2", category: "Nozomi" },
 { sysId: "", time: demoTime(80), priority: 4, priorityLabel: "LOW", description: "ARMIS integration heartbeat OK — 847 devices monitored", category: "ARMIS" },
];

interface Props { refreshKey: number; }

export default function AlertStream({ refreshKey }: Props) {
 const [alerts, setAlerts] = useState<Alert[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 let cancelled = false;
 async function load() {
 setLoading(true);
 const cf = companyFilter();
 const q = [
 "sys_created_onRELATIVEGE@dayofweek@ago@1",
 "ORDERBYDESCsys_created_on",
 cf,
 ].filter(Boolean).join("^");

 const rows = await fetchRecords(
 "sn_si_incident", q,
 "sys_id,sys_created_on,priority,short_description,category",
 15,
 );
 if (cancelled) return;

 const live: Alert[] = rows.map((r: any) => ({
 sysId: r.sys_id?.value ?? r.sys_id ?? "",
 time: formatTime(r.sys_created_on?.value || ""),
 priority: parseInt(r.priority?.value ?? "4", 10),
 priorityLabel: PRI_LABELS[parseInt(r.priority?.value ?? "4", 10)] || "LOW",
 description: r.short_description?.display_value || r.short_description?.value || "",
 category: r.category?.display_value || r.category?.value || "",
 }));

 setAlerts(live.length > 0 ? live : DEMO_ALERTS);
 setLoading(false);
 }
 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 return (
 <div className="ct-feed">
 <div className="ct-section-label">Alert Stream</div>
 {loading && <div className="ct-feed__empty">Loading…</div>}
 {!loading && alerts.length === 0 && (
 <div className="ct-feed__empty">No data for current filters</div>
 )}
 <div className="ct-feed__list">
 {alerts.map((a, i) => (
 <div key={a.sysId || i} className="ct-feed-row">
 <span className="ct-feed-row__time">{a.time}</span>
 <span className="ct-feed-badge" style={{ background: PRI_COLORS[a.priority] }}>
 {a.priorityLabel}
 </span>
 {a.sysId ? (
 <a className="ct-feed-row__link" href={recordUrl(a.sysId)} target="_top" title={a.description}>
 {truncate(a.description, 60)}
 </a>
 ) : (
 <span className="ct-feed-row__desc" title={a.description}>
 {truncate(a.description, 60)}
 </span>
 )}
 <span className="ct-feed-row__meta">{truncate(a.category, 18)}</span>
 </div>
 ))}
 </div>
 </div>
 );
}
