","/**
 * Defines the 5-table data source configuration for the
 * Unified Event Log. Each entry maps a ServiceNow table to
 * the fields needed to normalise records into a common schema.
 */

export interface SourceDef {
 table: string;
 label: string; // "Security", "OT Incident", …
 color: string; // badge colour
 companyField: string; // field name for the company filter
 fields: string; // sysparm_fields
 queryBase: string; // extra encoded-query clauses
 limit: number;
 mapRecord: (r: any) => EventRow;
}

export interface EventRow {
 id: string;
 timestamp: string; // raw ISO for sorting
 timeDisplay: string; // formatted for display
 type: string;
 typeColor: string;
 number: string;
 table: string;
 sysId: string;
 description: string;
 priority: number;
 priorityLabel: string;
 customer: string;
 site: string;
 state: string;
 assignedTo: string;
}

/* helper — keep priority mapping consistent */
const PRI: Record<number, string> = { 1: "Critical", 2: "High", 3: "Medium", 4: "Low", 5: "Planning" };

function pri(r: any): { p: number; l: string } {
 const v = parseInt(r.priority?.value ?? "4", 10);
 return { p: v, l: PRI[v] || "Low" };
}

function ts(r: any, field = "sys_created_on"): { raw: string; disp: string } {
 const raw = r[field]?.value || "";
 let disp = raw.slice(0, 16);
 try {
 const d = new Date(raw.replace(" ", "T") + "Z");
 disp = d.toLocaleString("en-US", { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit", hour12: false });
 } catch { /* keep slice */ }
 return { raw, disp };
}

function dv(r: any, f: string): string { return r[f]?.display_value || r[f]?.value || ""; }

export const SOURCES: SourceDef[] = [
 {
 table: "sn_si_incident",
 label: "Security",
 color: "#f44336",
 companyField: "company",
 fields: "sys_id,sys_created_on,number,short_description,priority,company,state,assigned_to,category",
 queryBase: "ORDERBYDESCsys_created_on",
 limit: 10,
 mapRecord: (r) => {
 const { p, l } = pri(r); const { raw, disp } = ts(r);
 return { id: r.sys_id?.value, timestamp: raw, timeDisplay: disp,
 type: "Security", typeColor: "#f44336", number: dv(r, "number"),
 table: "sn_si_incident", sysId: r.sys_id?.value,
 description: dv(r, "short_description"), priority: p, priorityLabel: l,
 customer: dv(r, "company"), site: "", state: dv(r, "state"),
 assignedTo: dv(r, "assigned_to") };
 },
 },
 {
 table: "sn_ot_incident",
 label: "OT Incident",
 color: "#ff9800",
 companyField: "company",
 fields: "sys_id,sys_created_on,number,short_description,priority,company,isa_entity_site,state,assigned_to",
 queryBase: "ORDERBYDESCsys_created_on",
 limit: 10,
 mapRecord: (r) => {
 const { p, l } = pri(r); const { raw, disp } = ts(r);
 return { id: r.sys_id?.value, timestamp: raw, timeDisplay: disp,
 type: "OT Incident", typeColor: "#ff9800", number: dv(r, "number"),
 table: "sn_ot_incident", sysId: r.sys_id?.value,
 description: dv(r, "short_description"), priority: p, priorityLabel: l,
 customer: dv(r, "company"), site: dv(r, "isa_entity_site"),
 state: dv(r, "state"), assignedTo: dv(r, "assigned_to") };
 },
 },
 {
 table: "sn_ot_change_request",
 label: "Change",
 color: "#4fc3f7",
 companyField: "company",
 fields: "sys_id,sys_updated_on,number,short_description,priority,company,isa_entity_site,state,assigned_to,risk",
 queryBase: "ORDERBYDESCsys_updated_on",
 limit: 5,
 mapRecord: (r) => {
 const { p, l } = pri(r); const { raw, disp } = ts(r, "sys_updated_on");
 return { id: r.sys_id?.value, timestamp: raw, timeDisplay: disp,
 type: "Change", typeColor: "#4fc3f7", number: dv(r, "number"),
 table: "sn_ot_change_request", sysId: r.sys_id?.value,
 description: dv(r, "short_description"), priority: p, priorityLabel: l,
 customer: dv(r, "company"), site: dv(r, "isa_entity_site"),
 state: dv(r, "state"), assignedTo: dv(r, "assigned_to") };
 },
 },
 {
 table: "sn_customerservice_case",
 label: "Case",
 color: "#66bb6a",
 companyField: "account",
 fields: "sys_id,sys_created_on,number,short_description,priority,account,state,assigned_to",
 queryBase: "ORDERBYDESCsys_created_on",
 limit: 5,
 mapRecord: (r) => {
 const { p, l } = pri(r); const { raw, disp } = ts(r);
 return { id: r.sys_id?.value, timestamp: raw, timeDisplay: disp,
 type: "Case", typeColor: "#66bb6a", number: dv(r, "number"),
 table: "sn_customerservice_case", sysId: r.sys_id?.value,
 description: dv(r, "short_description"), priority: p, priorityLabel: l,
 customer: dv(r, "account"), site: "", state: dv(r, "state"),
 assignedTo: dv(r, "assigned_to") };
 },
 },
 {
 table: "sn_vul_vulnerable_item",
 label: "Vuln",
 color: "#ab47bc",
 companyField: "cmdb_ci.company",
 fields: "sys_id,sys_created_on,number,short_description,risk_rating,cmdb_ci,state,assigned_to",
 queryBase: "ORDERBYDESCsys_created_on",
 limit: 5,
 mapRecord: (r) => {
 const rr = parseInt(r.risk_rating?.value ?? "4", 10);
 const rl = { 1: "Critical", 2: "High", 3: "Medium", 4: "Low", 5: "None" }[rr] || "Low";
 const { raw, disp } = ts(r);
 return { id: r.sys_id?.value, timestamp: raw, timeDisplay: disp,
 type: "Vuln", typeColor: "#ab47bc", number: dv(r, "number"),
 table: "sn_vul_vulnerable_item", sysId: r.sys_id?.value,
 description: dv(r, "short_description"), priority: rr, priorityLabel: rl,
 customer: dv(r, "cmdb_ci"), site: "", state: dv(r, "state"),
 assignedTo: dv(r, "assigned_to") };
 },
 },
];
","import React from "react";
import { useEventLog } from "../hooks/useEventLog";

const PRI_COLORS: Record<number, string> = {
 1: "#f44336", 2: "#ff9800", 3: "#4fc3f7", 4: "#484f58", 5: "#484f58",
};

function truncate(s: string, n: number): string {
 return s.length > n ? s.slice(0, n) + "…" : s;
}

interface Props { refreshKey: number; }

export default function EventLog({ refreshKey }: Props) {
