 {r.type}
 </span>
 </td>
 <td className="ct-elog__td ct-elog__td--num">
 <a
 className="ct-elog__link"
 href={`/now/workspace/customer-site-ops/record/${r.table}/${r.sysId}`}
 target="_top"
 title={`Open ${r.number}`}
 >{r.number}</a>
 </td>
 <td className="ct-elog__td ct-elog__td--desc" title={r.description}>
 {truncate(r.description, 60)}
 </td>
 <td className="ct-elog__td">
 <span className="ct-elog__pri-badge" style={{ background: PRI_COLORS[r.priority] }}>
 {r.priorityLabel}
 </span>
 </td>
 <td className="ct-elog__td ct-elog__td--cust" title={r.customer}>
 {truncate(r.customer, 20)}
 </td>
 <td className="ct-elog__td ct-elog__td--site" title={r.site}>
 {truncate(r.site || "—", 18)}
 </td>
 <td className="ct-elog__td ct-elog__td--state">{r.state}</td>
 <td className="ct-elog__td ct-elog__td--assign" title={r.assignedTo}>
 {truncate(r.assignedTo || "—", 16)}
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 </div>
 );
}
","import { useState, useEffect } from "react";
import { fetchRecords, getFilterParams } from "../services/api";
import { SOURCES, EventRow } from "../services/eventSources";

const MAX_ROWS = 25;

/**
 * Fetches records from all 5 tables in parallel, normalises
 * each into EventRow, merges and sorts descending by timestamp.
 * Returns at most MAX_ROWS entries.
 */
export function useEventLog(refreshKey: number) {
 const [rows, setRows] = useState<EventRow[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 let cancelled = false;

 async function load() {
 setLoading(true);
 const { company, site } = getFilterParams();

 const fetches = SOURCES.map((src) => {
 let q = src.queryBase;
 if (company) q = `${src.companyField}=${company}^${q}`;
 if (site && src.fields.includes("isa_entity_site"))
 q = `isa_entity_site=${site}^${q}`;

 return fetchRecords(src.table, q, src.fields, src.limit)
 .then((recs) => recs.map(src.mapRecord))
 .catch(() => [] as EventRow[]);
 });

 const results = await Promise.all(fetches);
 if (cancelled) return;

 const merged = results
 .flat()
 .sort((a, b) => (b.timestamp > a.timestamp ? 1 : -1))
 .slice(0, MAX_ROWS);

 setRows(merged);
 setLoading(false);
 }

 load();
 return () => { cancelled = true; };
 }, [refreshKey]);

 return { rows, loading };
}
