import "./control-tower.css";

const FAST_INTERVAL = 30_000; // 30s — feeds, event log, line status
const SLOW_INTERVAL = 60_000; // 60s — map, charts, gauges

export default function App() {
 const [fastKey, setFastKey] = useState(0);
 const [slowKey, setSlowKey] = useState(0);

 useEffect(() => {
 const f = setInterval(() => setFastKey((k) => k + 1), FAST_INTERVAL);
 const s = setInterval(() => setSlowKey((k) => k + 1), SLOW_INTERVAL);
 return () => { clearInterval(f); clearInterval(s); };
 }, []);

 return (
 <div className="ct-page">
 <StatusBar />

 <main className="ct-columns">
 <Panel title="Production Lines">
 <LineStatusPanel refreshKey={fastKey} />
 <DeviceHealth refreshKey={fastKey} />
 <MaintenanceWindows refreshKey={fastKey} />
 </Panel>

 <Panel title="Monitoring Center" wide>
 <IncidentMap refreshKey={slowKey} />
 <AlertsBySource refreshKey={slowKey} />
 <VulnGauges refreshKey={slowKey} />
 <PurdueStatus refreshKey={slowKey} />
 </Panel>

 <Panel title="Event Feed">
